const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:3333';

export const api = {
  url: API_URL,

  getCategories: () => fetch(`${API_URL}/categories`).then(res => res.json()),
  getProducts: () => fetch(`${API_URL}/products`).then(res => res.json()),

  // Если нужно получить картинку — просто формируем URL
  getCategoryImageUrl: (imageName) => `${API_URL}/category_img/${imageName}`,
};

export default api;
